\boxed{
\begin{aligned}
&\text{seperti:}\\
&\text{x+y=1} \Rightarrow x = 1 - y \\
&\text{y-2z=-3} \Rightarrow y = 2z - 3 \\
&\text{2x+z=5} \Rightarrow 2(1 - y) + z = 5 \\
&\Rightarrow 2 - 2y + z = 5 \\
&\Rightarrow z = 3 + 2y
\end{aligned}
}

Lanjutkan:
\boxed{
\begin{aligned}
x + y &= 1 \\
y - 2z &= -3 \\
2x + z &= 5
\end{aligned}
}

